INSERT INTO ideas VALUES(25,'7 Things Claude Does for Business Owners','7 things Claude is doing for my business right now.','quick_tip','proof',NULL,NULL,NULL,NULL,'filmed',NULL,NULL,NULL,'2026-04-21 23:35:42');
INSERT INTO ideas VALUES(26,'What is Claude','Everyone talks about Claude. Nobody tells you what it actually is.','education',NULL,'AI Tools',NULL,NULL,NULL,'filmed',NULL,NULL,NULL,'2026-04-23 05:05:16');
INSERT INTO scripts VALUES(1,1,'reel',unistr('[HOOK] Everyone''s talking about AI agents. Nobody explains what they actually are. 60 seconds. No jargon.\u000a\u000a[EXPLAIN] An AI agent is software that does tasks for you. Not just answers questions. It DOES the work. It reads your emails. It writes the reply. It sends it. Without you touching anything.\u000a\u000a[ILLUSTRATE] Think of it like hiring someone. But they work 24/7. They never forget. They never call in sick. And they cost $0 a month. You tell them once what to do. They do it forever.\u000a\u000a[TAKEAWAY] Start small. Pick ONE task you do every day. Ask AI to do it. That''s your first agent. Follow for more.'),112,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(2,2,'reel',unistr('[HOOK] 70% of AI projects fail. Not because AI is bad. Because people skip this one thing.\u000a\u000a[EXPLAIN] Everyone buys tools. ChatGPT. Zapier. Make. They connect things. It breaks. They quit. The problem isn''t the tool. It''s that they don''t have a SYSTEM.\u000a\u000a[ILLUSTRATE] A tool is a hammer. A system is the blueprint for the house. I bought every AI tool out there. Nothing worked. Then I stopped buying tools. I mapped out my process first. Then I told AI to follow it. Everything changed.\u000a\u000a[TAKEAWAY] Before you touch any AI tool — write down your process. Step by step. That''s the system. AI follows systems. It can''t follow chaos. Follow for more.'),119,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(3,3,'reel',unistr('[HOOK] You''re losing clients right now. Not because your work is bad. Because you''re too slow.\u000a\u000a[EXPLAIN] Speed to lead. The first business to reply wins the job. 78% of the time. But you''re busy working. So the lead sits there. For hours. Sometimes days.\u000a\u000a[ILLUSTRATE] I used to lose deals every week. Same reason. Slow follow-up. So I set up AI to reply in minutes. Not hours. Not days. Minutes. The client gets a message before I even see the lead.\u000a\u000a[TAKEAWAY] Time kills deals. Set up one auto-reply for new leads. Just one. That alone will save you clients this week. Follow for more.'),111,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(4,4,'reel',unistr('[HOOK] This is a cheat code. AI can write every email you send. Same words you''d use. In 10 seconds.\u000a\u000a[EXPLAIN] You write the same types of emails every day. Follow-ups. Quotes. Thank yous. Scheduling. AI learns your tone. Then it drafts them for you. You just hit send.\u000a\u000a[ILLUSTRATE] I used to spend an hour a day on emails. Now AI writes the draft. I read it. Change one word. Maybe two. Send. Takes 10 seconds per email. Same voice. Clients can''t tell the difference.\u000a\u000a[TAKEAWAY] Copy 10 emails you''ve already sent. Paste them into AI. Say "write like this." That''s it. Your AI just learned your voice. Follow for more.'),121,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(5,5,'reel',unistr('[HOOK] 5 things you''re still doing by hand. AI does all of them. For free.\u000a\u000a[EXPLAIN] Most people use AI to chat. That''s like buying a car and only sitting in it. Here are 5 things AI can actually DO for your business.\u000a\u000a[ILLUSTRATE] One — writing emails. AI drafts them in your voice. Two — follow-ups. AI sends them on time. Every time. Three — scheduling. AI books your meetings. Four — reports. AI pulls your numbers and summarizes them. Five — data entry. AI reads documents and fills in your system. Number three saved me 10 hours a week.\u000a\u000a[TAKEAWAY] Pick one from the list. Automate it this week. Start with the one that wastes the most time. Follow for more.'),122,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(6,6,'reel',unistr('[HOOK] ChatGPT sounds like a robot. That''s not AI''s fault. You''re using it wrong.\u000a\u000a[EXPLAIN] Everyone types "write me an email" and gets corporate garbage. AI doesn''t know your voice. You never taught it. One trick fixes this.\u000a\u000a[ILLUSTRATE] Copy 10 emails you''ve already written. Paste them into AI. Tell it "study how I write. Match this tone." Now every email sounds like you. Not like a machine. I did this for my work. My clients have no idea AI writes my emails.\u000a\u000a[TAKEAWAY] Go to your sent folder right now. Copy 10 messages. Feed them to AI. That''s 5 minutes of work. You''ll never write from scratch again. Follow for more.'),118,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(7,7,'reel',unistr('[HOOK] Every quote I sent took 45 minutes. Now it takes 5. Same quality. Here''s what changed.\u000a\u000a[EXPLAIN] The old way: drive to the site. Measure everything. Come back. Open a template. Type it up. Format it. Email it. That''s 45 minutes if you''re fast. Most businesses do this every day.\u000a\u000a[ILLUSTRATE] I built a system. AI reads the job details. It picks the right template. It fills in the scope, the pricing, the terms. Creates the document. Drafts the email. My team reviews it. Hits send. 5 minutes.\u000a\u000a[TAKEAWAY] You don''t need my exact system. Start with one template. Feed it to AI. Tell it to fill in the blanks next time. That''s step one. Follow for more.'),127,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(8,8,'reel',unistr('[HOOK] My team manages 80+ deals at once. Sounds insane. It''s actually boring. And that''s the point.\u000a\u000a[EXPLAIN] Most businesses lose deals because things slip. Forgot to follow up. Missed a call. Lost the email. The more deals you have, the more you drop.\u000a\u000a[ILLUSTRATE] We built AI to track every deal. It tells us who needs a follow-up. It flags deals going cold. It drafts the message. My team just reviews and sends. No spreadsheets. No sticky notes. No guessing. It''s boring. Nothing falls through the cracks.\u000a\u000a[TAKEAWAY] You don''t need 80 deals to start. If you have 5 deals right now, AI can track them. Set up reminders and auto-drafts for follow-ups. Boring systems win. Follow for more.'),131,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(9,9,'reel',unistr('[HOOK] I used to waste 2 hours every morning. Emails. CRM. Follow-ups. Now AI does all of it before I wake up.\u000a\u000a[EXPLAIN] Every morning you open your laptop and do the same thing. Check emails. Check your pipeline. Write follow-ups. Review yesterday''s numbers. It''s 2 hours of work that adds zero value.\u000a\u000a[ILLUSTRATE] I built a morning briefing. AI checks my emails overnight. Scans my CRM. Flags what needs attention. Drafts the follow-ups. By 5:30 AM, everything''s done. I wake up, read the summary, approve what''s ready. 10 minutes.\u000a\u000a[TAKEAWAY] Start with one thing. Set AI to check your inbox every morning and list what needs a reply. That alone saves 30 minutes a day. Follow for more.'),128,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(10,10,'reel',unistr('[HOOK] You don''t need to code. You don''t need to be technical. I told AI what I needed in plain English. It built the whole system.\u000a\u000a[EXPLAIN] This is 2026. AI doesn''t need you to write code. You describe what you want. Step by step. In normal words. AI builds it.\u000a\u000a[ILLUSTRATE] I''m a sales guy. Zero coding background. I told AI "when a new lead comes in, check the CRM, draft a follow-up, and schedule it." That''s it. That''s what I typed. AI built the automation. It runs every day. No code. No developer. Just plain English.\u000a\u000a[TAKEAWAY] Describe one process you do every day. Write it like you''re explaining it to a new hire. Paste it into AI. Let it build the system. Follow for more.'),132,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(11,11,'reel',unistr('[HOOK] 3 months ago we turned on AI follow-ups. Since then? Zero leads lost. Not one.\u000a\u000a[EXPLAIN] Before this, leads slipped every week. Someone forgot to call back. An email got buried. A quote went out late. Normal stuff. But normal costs you money.\u000a\u000a[ILLUSTRATE] Now AI watches every lead. If nobody replies in 24 hours, AI sends a follow-up. If a deal goes quiet for 3 days, AI flags it. My team gets a notification. The client gets a message. Nothing sits. Nothing dies. Zero leads lost in 3 months.\u000a\u000a[TAKEAWAY] You don''t need a fancy system. Set one rule: if no reply in 24 hours, send a follow-up. Automate that one rule. It''ll change your business. Follow for more.'),127,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(12,12,'reel',unistr('[HOOK] Every business owner needs a dashboard. Most pay thousands for one. Here''s how to build it in 10 minutes. Free. No code.\u000a\u000a[EXPLAIN] A dashboard shows you what''s happening in your business. Deals. Revenue. Follow-ups due. Tasks. Most people use spreadsheets. Or nothing. A real dashboard takes hours to build. Unless you use AI.\u000a\u000a[ILLUSTRATE] I told AI what I wanted to see. My active deals. My revenue this month. What''s overdue. AI built the dashboard. It pulls live data. Updates itself. Took 10 minutes. Looks better than anything I could''ve designed. Cost me $0.\u000a\u000a[TAKEAWAY] Open AI. Tell it "build me a dashboard that shows my sales pipeline." Be specific about what you want to see. It''ll build it. 10 minutes. Follow for more.'),131,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(13,13,'reel',unistr('[HOOK] I''m not a tech guy. I''m not a developer. I''m a sales guy from the Philippines. And I manage over $100K a month in revenue with AI.\u000a\u000a[EXPLAIN] Everyone thinks you need to be technical to use AI. You don''t. You need to know your problems. AI needs problems to solve. That''s it.\u000a\u000a[ILLUSTRATE] I couldn''t code. Still can''t. But I knew what wasted my time. Quotes took too long. Follow-ups got missed. Leads went cold. I told AI about each problem. One by one. It built the fix. Now my team runs a full pipeline with AI doing the heavy lifting.\u000a\u000a[TAKEAWAY] Don''t learn to code. Learn to describe your problems clearly. That''s the only skill AI needs from you. Follow for more.'),124,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(14,14,'reel',unistr('[HOOK] AI won''t replace you. But someone using AI will. And it''s already happening.\u000a\u000a[EXPLAIN] Your competitor just sent a quote in 5 minutes. Yours takes 45. Your competitor followed up same day. You forgot. Your competitor runs 80 deals. You drop 5.\u000a\u000a[ILLUSTRATE] This isn''t about being smarter. It''s about being faster. The business that replies first wins 78% of the time. AI makes you first. Every time. Not because you work harder. Because your system never sleeps.\u000a\u000a[TAKEAWAY] You don''t need to automate everything today. Pick the one thing that loses you the most money. Speed it up with AI. That''s your edge. Follow for more.'),116,'2026-04-21 12:13:28');
INSERT INTO scripts VALUES(15,23,'reel','[filmed]',NULL,'2026-04-21 23:35:42');
