INSERT INTO scripts VALUES(32,25,'caption_x',unistr('Everyone''s asking what AI can do for their business.\u000a\u000aHere are 7 things Claude is doing for mine — right now.\u000a\u000aI''m not a developer. Built all of this in 2 weeks.\u000a\u000aWhich one would you want set up first?\u000a\u000a#ClaudeAI #AI #BusinessAutomation'),43,'2026-04-21 23:35:42');
INSERT INTO scripts VALUES(33,25,'caption_linkedin',unistr('7 things Claude is doing for my business.\u000a\u000aMost people use AI for answers. This is different.\u000a\u000a1. Builds a full website — one prompt\u000a2. Builds a working app — plain English in\u000a3. 30 days of content — from your competitors'' top posts\u000a4. Spies on competitors — pricing, ads, reviews in 10 min\u000a5. Finds your next hire — writes outreach while you sleep\u000a6. 200 leads with personal emails — written and sent\u000a7. Revives dead CRM deals — money you already earned\u000a\u000aWhich one would save you the most time?\u000a\u000aComment SEVEN — I''ll help you build it for free.\u000a\u000a#ClaudeAI #BusinessAutomation #AIForBusiness'),87,'2026-04-23 05:05:10');
